"""Kaggle kernel: Track B top-tier confirmatory audit.

Runs the Track B downstream-control lane with richer metric capture:
order-level Excel ReT, CD components, tail/CVaR panel, and Garrido-style
per-order ledger CSV.  The workbook itself is built locally after download
because the Codex artifact-tool runtime is not available on Kaggle.
"""

from __future__ import annotations

from datetime import datetime, timezone
import base64
import json
import os
from pathlib import Path
import shutil
import subprocess
import sys
import tarfile
from typing import Any


PAYLOAD = Path("/kaggle/input/scres-ia-payload/scres_ia_payload.tar.gz")
SCRIPT_PAYLOAD = Path(__file__).resolve().with_name("scres_ia_payload.tar.gz")
REPO_DIR = Path("/kaggle/working/scres-ia")
OUTPUT_DIR = Path("/kaggle/working/track_b_top_tier_confirm_5seed_60k_h104")
AUDIT_DIR = OUTPUT_DIR / "top_tier_audit"


def run(cmd: list[str], cwd: Path | None = None) -> None:
    print("$ " + " ".join(cmd), flush=True)
    subprocess.run(cmd, cwd=str(cwd) if cwd else None, check=True)


def find_payload() -> Path:
    candidates = [PAYLOAD, SCRIPT_PAYLOAD, Path("scres_ia_payload.tar.gz")]
    candidates.extend(sorted(Path("/kaggle/input").glob("**/scres_ia_payload.tar.gz")))
    for candidate in candidates:
        if candidate.exists():
            return candidate
    if EMBEDDED_PAYLOAD_B64.strip():
        target = Path("/kaggle/working/scres_ia_payload.tar.gz")
        print(f"[kernel] writing embedded payload {target}", flush=True)
        target.write_bytes(base64.b64decode(EMBEDDED_PAYLOAD_B64))
        return target
    raise FileNotFoundError(
        "Missing scres_ia_payload.tar.gz in Kaggle input. "
        "Update the thomaschisica/scres-ia-payload dataset before pushing."
    )


def extract_payload() -> None:
    payload = find_payload()
    print(f"[kernel] extracting payload {payload}", flush=True)
    if REPO_DIR.exists():
        shutil.rmtree(REPO_DIR)
    REPO_DIR.mkdir(parents=True, exist_ok=True)
    with tarfile.open(payload, "r:gz") as archive:
        archive.extractall(REPO_DIR)


def load_json(path: Path) -> dict[str, Any]:
    return json.loads(path.read_text(encoding="utf-8"))


def summarize() -> dict[str, Any]:
    audit_json = AUDIT_DIR / "track_b_top_tier_audit.json"
    if audit_json.exists():
        audit = load_json(audit_json)
        verdicts = {
            row["verdict"]: row
            for row in audit.get("verdicts", [])
            if isinstance(row, dict) and "verdict" in row
        }
        return {
            "summary_path": str(OUTPUT_DIR / "summary.json"),
            "audit_path": str(audit_json),
            "learned_policy": audit.get("learned_policy"),
            "best_static_policy": audit.get("best_static_policy"),
            "verdicts": verdicts,
            "raw_ret_win": bool(verdicts.get("raw_ret_win", {}).get("pass", False)),
            "ret_tail_win": bool(verdicts.get("ret_tail_win", {}).get("pass", False)),
            "pareto_ret_cost": bool(verdicts.get("pareto_ret_cost", {}).get("pass", False)),
            "resource_efficient_win": bool(
                verdicts.get("resource_efficient_win", {}).get("pass", False)
            ),
        }
    return {"summary_path": str(OUTPUT_DIR / "summary.json")}


def main() -> int:
    os.environ.setdefault("CUDA_VISIBLE_DEVICES", "")
    os.environ.setdefault("PYTHONUNBUFFERED", "1")
    started = datetime.now(timezone.utc)
    print("SCRESIA Track B top-tier confirm", started.isoformat(), flush=True)

    try:
        extract_payload()
        run([sys.executable, "-m", "pip", "install", "-q", "-r", "requirements.txt"], cwd=REPO_DIR)
        OUTPUT_DIR.mkdir(parents=True, exist_ok=True)

        run(
            [
                sys.executable,
                "scripts/run_track_b_smoke.py",
                "--output-dir",
                str(OUTPUT_DIR),
                "--seeds",
                "1",
                "2",
                "3",
                "4",
                "5",
                "--train-timesteps",
                "60000",
                "--eval-episodes",
                "12",
                "--export-order-ledger",
                "--reward-mode",
                "control_v1",
                "--risk-level",
                "adaptive_benchmark_v2",
                "--observation-version",
                "v7",
                "--max-steps",
                "104",
                "--n-steps",
                "1024",
                "--batch-size",
                "256",
                "--learning-rate",
                "3e-4",
            ],
            cwd=REPO_DIR,
        )

        run(
            [
                sys.executable,
                "scripts/build_track_b_top_tier_audit.py",
                "--run-dir",
                str(OUTPUT_DIR),
                "--output-dir",
                str(AUDIT_DIR),
                "--ledger-max-rows",
                "100000",
                "--no-workbook",
            ],
            cwd=REPO_DIR,
        )

        decision = summarize()
        decision.update(
            {
                "started_at": started.isoformat(),
                "finished_at": datetime.now(timezone.utc).isoformat(),
                "profile": "track_b_top_tier_confirm_5seed_60k_h104",
            }
        )
        (OUTPUT_DIR / "decision.json").write_text(json.dumps(decision, indent=2, default=float))
        print("\n=== TRACK B TOP-TIER CONFIRM DECISION ===", flush=True)
        print(json.dumps(decision, indent=2, default=float), flush=True)
        return 0
    finally:
        # Keep Kaggle output small and auditable.  Results remain in OUTPUT_DIR.
        if REPO_DIR.exists():
            shutil.rmtree(REPO_DIR, ignore_errors=True)


EMBEDDED_PAYLOAD_B64 = """

"""


if __name__ == "__main__":
    raise SystemExit(main())
